#!/usr/bin/env python3
"""el_mendeley — ElevenLabs & Respeecher fake speech (Mendeley Data 79g59sp69z, v1).

"Dataset of synthetic voices generated by ElevenLabs and Respeecher" — 2025-vintage
commercial TTS/voice-conversion clips with per-file metadata (metadata.xlsx).
Direct public download (CC-BY-4.0). Pooled like every other source.

Usage: .venv/bin/python prep.py all   (or download / stage) [--limit N]
"""
from __future__ import annotations

import argparse
import sys
import zipfile
from pathlib import Path

SRC_DIR = Path(__file__).resolve().parent
DATASET_ROOT = SRC_DIR.parents[1]
sys.path.insert(0, str(DATASET_ROOT))

from common.staging import StagingWriter, StagedClip  # noqa: E402
from common.audio import decode_to_staged_wav, codec_history_label, ffprobe_info  # noqa: E402

SOURCE = "el_mendeley"
RAW = SRC_DIR / "raw"
API = "https://data.mendeley.com/public-api/datasets/79g59sp69z/files?folder_id=root&version=1"
DATASET_URI = "https://data.mendeley.com/datasets/79g59sp69z/1"


def do_download():
    import requests
    RAW.mkdir(parents=True, exist_ok=True)
    files = requests.get(API, timeout=30).json()
    for f in files:
        name, url = f["filename"], f["content_details"]["download_url"]
        dst = RAW / name
        if dst.exists() and dst.stat().st_size == f.get("size", -1):
            print(f"[{SOURCE}] cached {name}")
            continue
        print(f"[{SOURCE}] downloading {name} ({f.get('size',0)/1e6:.0f} MB)")
        with requests.get(url, stream=True, timeout=120) as r:
            r.raise_for_status()
            with open(dst, "wb") as out:
                for chunk in r.iter_content(1 << 20):
                    out.write(chunk)
    zips = list(RAW.glob("*.zip"))
    for z in zips:
        marker = RAW / (z.stem + ".extracted")
        if marker.exists():
            continue
        print(f"[{SOURCE}] extracting {z.name}")
        with zipfile.ZipFile(z) as zf:
            zf.extractall(RAW / "extracted")
        marker.touch()
    print(f"[{SOURCE}] download done")


def _load_metadata() -> dict[str, dict]:
    """metadata.xlsx -> {audio_stem: {tool, type, gender, age, fs}}.

    Verified layout (v1): columns Audio | Tool | Type | Gender | Age_group | Fs |
    Time(s), e.g. ('audio1', 'ElevenLabs', 'V2V', 'M', 'adulto', 22050, 9)."""
    import openpyxl
    meta: dict[str, dict] = {}
    xlsx = RAW / "metadata.xlsx"
    if not xlsx.exists():
        sys.exit(f"[{SOURCE}] metadata.xlsx missing; run download first")
    wb = openpyxl.load_workbook(xlsx, read_only=True)
    ws = wb.active
    rows = ws.iter_rows(values_only=True)
    next(rows)  # header
    for r in rows:
        if not r or not r[0]:
            continue
        meta[str(r[0]).strip()] = {
            "tool": str(r[1] or "").strip(),
            "type": str(r[2] or "").strip(),
            "gender": str(r[3] or "").strip(),
            "age": str(r[4] or "").strip(),
            "fs": str(r[5] or "").strip(),
        }
    return meta


def do_stage(limit: int | None):
    audio_files = sorted(p for p in (RAW / "extracted").rglob("*")
                         if p.suffix.lower() in (".wav", ".mp3", ".flac", ".ogg", ".m4a"))
    if not audio_files:
        sys.exit(f"[{SOURCE}] nothing extracted; run download first")
    if limit:
        audio_files = audio_files[:limit]
    meta = _load_metadata()
    w = StagingWriter(SRC_DIR, SOURCE)
    for i, src in enumerate(audio_files):
        m = meta.get(src.stem)
        if not m:
            w.skip("no_metadata_row")
            continue
        tool = m["tool"].lower()
        if "eleven" in tool:
            family = gen = "elevenlabs"
        elif "respeecher" in tool:
            family = gen = "respeecher"
        else:
            w.skip(f"unknown_tool:{tool[:20]}")
            continue
        kind = m["type"].lower()  # v2v (voice conversion) or tts
        dst = w.next_clip_path(i)
        try:
            info = decode_to_staged_wav(src, dst)
        except Exception:
            w.skip("decode_error")
            continue
        w.add(StagedClip(
            staged_path=str(dst.relative_to(SRC_DIR)),
            source=SOURCE, label="fake", language="en", domain="studio",
            generator=gen, generator_family=family,
            generator_version="2025_h1",
            synthesis_paradigm="unknown",
            generation_date="2025", vintage="2025",
            source_recording_id=f"{SOURCE}:{src.stem}",
            utterance_id=src.stem,
            source_uri=DATASET_URI,
            source_license="cc_by_4.0",
            codec_history=codec_history_label(src.suffix.lstrip(".")),
            native_sample_rate_hz=info["sample_rate"],
            duration_s=round(info["duration_s"], 3),
            test_only="0",
            notes=f"type={kind};gender={m['gender']}",
        ))
    stats = w.finish({"dataset": DATASET_URI})
    print(f"[{SOURCE}] staged {stats['clips']} ({stats['hours']} h) "
          f"by_gen={stats['by_generator']} skipped={stats['skipped']}")


if __name__ == "__main__":
    ap = argparse.ArgumentParser()
    ap.add_argument("cmd", choices=["download", "stage", "all"])
    ap.add_argument("--limit", type=int, default=None)
    a = ap.parse_args()
    if a.cmd in ("download", "all"):
        do_download()
    if a.cmd in ("stage", "all"):
        do_stage(a.limit)
